#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new();
my $log_dir = "/path/to/log/directory";
my $logfile = $cgi->param('logfile');

if ($logfile) {
    my $full_path = "$log_dir/$logfile";

    # Check if the file exists and is in the log directory
    if (-e $full_path && -f $full_path && $full_path =~ /^\Q$log_dir\E\/[^\/]+$/) {
        open(my $fh, '<', $full_path) or die "Cannot open '$full_path': $!";

        print "Content-type: text/plain\n\n";
        while (my $line = <$fh>) {
            print $line;
        }
        close($fh);
    } else {
        print "Content-type: text/html\n\n";
        print "<html><body><p>Error: Invalid or unauthorized log file.</p></body></html>";
    }
} else {
    print "Content-type: text/html\n\n";
    print "<html><body><p>Error: No logfile parameter provided.</p></body></html>";
}